    int field_count = 1; // At least one field
    for (int i = 0; first_record[i] != '\0'; i++) {
        if (first_record[i] == ',') {
            field_count++;
        }
    }

    // Precompute field offsets and total record size
    int total_record_size = 0;
    int* field_offsets = (int*)malloc(field_count * sizeof(int));
    if (field_offsets == NULL) {
        return -1;
    }

    field_offsets[0] = 0;
    total_record_size = field_sizes[0];
    for (int j = 1; j < field_count; j++) {
        field_offsets[j] = field_offsets[j-1] + field_sizes[j-1];
        total_record_size += field_sizes[j];
    }

    // Allocate memory for parsed buffer
    size_t total_buffer_size = record_count * total_record_size;
    *parsed_buffer = (char*)malloc(total_buffer_size);
    if (*parsed_buffer == NULL) {
        free(field_offsets);
        return -1;
    }
    memset(*parsed_buffer, 0, total_buffer_size); // Initialize to zero

    // Process each record
    for (int i = 0; i < record_count; i++) {
        char* record_str = csv_data[i];
        if (record_str == NULL) {
            free(field_offsets);
            free(*parsed_buffer);
            *parsed_buffer = NULL;
            return -1;
        }

        // Count commas in current record
        int comma_count = 0;
        for (int j = 0; record_str[j] != '\0'; j++) {
            if (record_str[j] == ',') {
                comma_count++;
            }
        }

        // Validate field count
        if (comma_count != field_count - 1) {
            free(field_offsets);
            free(*parsed_buffer);
            *parsed_buffer = NULL;
            return -1;
        }

        // Tokenize record
        char* token_start = record_str;
        for (int j = 0; j < field_count; j++) {
            char* token_end = token_start;
            while (*token_end != ',' && *token_end != '\0') {
                token_end++;
            }

            size_t token_len = token_end - token_start;
            char* dest = *parsed_buffer + (i * total_record_size) + field_offsets[j];

            // Copy token data (truncate if necessary)
            size_t copy_len = token_len < (size_t)field_sizes[j] ? token_len : (size_t)field_sizes[j];
            memcpy(dest, token_start, copy_len);

            // Move to next token
            if (*token_end == ',') {
                token_start = token_end + 1;
            } else {
                token_start = token_end;
            }
        }
    }

    free(field_offsets);
    return 0;
}

